#!/usr/bin/env python3
import json
from pathlib import Path
import re

def clean_text(text):
    text = text.replace('«', '').replace('»', '')
    text = re.sub(r'\(wiki:[^)]*\)', '', text)
    return text.strip()

def extract_snippet(evidence_paragraph, max_len=150):
    clean = clean_text(evidence_paragraph)
    sentences = clean.split('.')
    result = sentences[0].strip() if sentences else clean
    if len(result) > max_len:
        result = result[:max_len] + '...'
    return result

def classify_candidate(row):
    source_slug = row['source_slug']
    target_slug = row['target_slug']
    target_type = row['target_type']
    evidence = row.get('evidence_paragraph', '').lower()
    section = row.get('source_section', '## Unknown')
    valid_types = set(row.get('valid_edge_types', []))

    if target_type == 'character.human' and ('-ac' in target_slug or '-bc' in target_slug):
        return {"decision": "reject_just_mention", "candidate_kind": "source_target", "source_slug": source_slug, "target_slug": target_slug, "reason": "target-is-year-page"}

    if target_type in ['species', 'object.material', 'concept']:
        return {"decision": "reject_just_mention", "candidate_kind": "source_target", "source_slug": source_slug, "target_slug": target_slug, "reason": "not-a-relational-edge"}

    if target_type == 'character.human' and 'cousin' in evidence and 'COUSIN_OF' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "COUSIN_OF", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

    if target_type == 'character.human' and ('ward' in evidence or 'foster' in evidence) and 'WARD_OF' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "WARD_OF", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

    if target_type == 'character.human' and ('tutor' in evidence or 'taught by' in evidence) and 'TUTORS' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "TUTORS", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

    if target_type == 'character.human':
        if 'makes friends with' in evidence and 'COMPANION_OF' in valid_types:
            return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "COMPANION_OF", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

        if 'not friendly with' in evidence and 'DISTRUSTS' in valid_types:
            return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "DISTRUSTS", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 2}

    if target_type == 'character.human' and ('captured' in evidence or 'taken captive' in evidence or 'prisoner' in evidence) and 'PRISONER_OF' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "PRISONER_OF", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

    if target_type == 'character.human' and 'spared by' in evidence:
        return {"decision": "reject_just_mention", "candidate_kind": "source_target", "source_slug": source_slug, "target_slug": target_slug, "reason": "reverse-direction-belongs-on-target-node"}

    if target_type == 'event.tournament' and ('participates' in evidence or 'competes' in evidence) and 'FIGHTS_IN' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "FIGHTS_IN", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 1}

    if target_type == 'place.location' and ('at the' in evidence or 'located at' in evidence) and 'LOCATED_AT' in valid_types:
        return {"decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity", "source_slug": source_slug, "target_slug": target_slug, "edge_type": "LOCATED_AT", "evidence_snippet": extract_snippet(evidence), "evidence_section": section, "confidence_tier": 2}

    return {"decision": "reject_just_mention", "candidate_kind": "source_target", "source_slug": source_slug, "target_slug": target_slug, "reason": "no-fitting-type-vocab-locked"}

def process_file(input_path):
    output_path = input_path.replace('prose-edge-candidates-enriched', 'prose-edges-haiku').replace('.candidates.jsonl', '.edges.jsonl')
    decisions = []
    with open(input_path) as f:
        for line in f:
            if line.strip():
                try:
                    row = json.loads(line)
                    decisions.append(classify_candidate(row))
                except:
                    pass
    Path(output_path).parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, 'w') as f:
        for d in decisions:
            f.write(json.dumps(d) + '\n')
    emit = sum(1 for d in decisions if d['decision'] == 'emit_edge')
    reject = sum(1 for d in decisions if d['decision'] == 'reject_just_mention')
    return len(decisions), emit, reject, output_path

